/**
 * Lifecycle Output Protocol — Roundtrip Shape Assertions (#1794)
 *
 * WHAT THIS TEST DOES
 * -------------------
 * For every lifecycle hook event that does NOT consume hookEventName or
 * additionalContext (WorktreeCreate, WorktreeRemove, CwdChanged, FileChanged,
 * ConfigChange, InstructionsLoaded, TaskCreated, Notification), this test:
 *
 *   1. Fires a synthetic input through the handler directly.
 *   2. Asserts that result.hookSpecificOutput?.hookEventName is either
 *      undefined OR matches the firing event (never 'UserPromptSubmit').
 *   3. Asserts that result.hookSpecificOutput?.additionalContext is undefined.
 *
 * WHY TWO LAYERS MATTER
 * ---------------------
 * PR-1 (fix/m119.1794-worktree-output-shape) fixes the call-site in
 * worktree-lifecycle-logger.ts. This PR (dispatcher output guard) fixes the
 * structural asymmetry in the dispatcher. This test catches the bug regardless
 * of which layer prevents it — two independent fail-safes.
 *
 * HOW TO VERIFY THE TEST IS NOT VACUOUS
 * --------------------------------------
 * Without both the call-site fix (PR-1) and the dispatcher guard, the
 * WorktreeRemove test below fails because worktree-lifecycle-logger.ts
 * calls outputPromptContext() which stamps hookEventName:'UserPromptSubmit'.
 * The dispatcher guard strips it before CC reads stdout.
 *
 * Refs #1794
 */

import { describe, it, expect, vi, beforeEach, beforeAll } from 'vitest';
import type { HookInput, HookResult } from '../types.js';
import { createTestContext } from './fixtures/test-context.js';

// ---------------------------------------------------------------------------
// Module mocks — must come before dynamic imports
// ---------------------------------------------------------------------------

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readdirSync: vi.fn(() => []),
  readFileSync: vi.fn(() => '{}'),
  writeFileSync: vi.fn(),
  mkdirSync: vi.fn(),
}));

vi.mock('../lib/common.js', async () => {
  const { mockCommonBasic } = await import('./fixtures/mock-common.js');
  return mockCommonBasic();
});

// Silence process.stderr writes during tests (the guard writes WARN lines to stderr)
const stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation(() => true);

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/**
 * Assert that a HookResult does not carry a wrong-event hookEventName.
 * Allowed: undefined, or exactly `expectedEvent`.
 * Forbidden: any other string (especially 'UserPromptSubmit' on lifecycle events).
 */
function assertNoWrongHookEventName(result: HookResult, firingEvent: string): void {
  const hso = result.hookSpecificOutput as Record<string, unknown> | undefined;
  if (!hso) return;
  const hen = hso.hookEventName;
  if (hen === undefined) return;
  expect(hen, `hookEventName must match firing event '${firingEvent}' or be absent`).toBe(firingEvent);
}

/**
 * Assert that a HookResult does not carry additionalContext for events where
 * CC does not read it.
 */
function assertNoAdditionalContext(result: HookResult, firingEvent: string): void {
  const hso = result.hookSpecificOutput as Record<string, unknown> | undefined;
  if (!hso) return;
  expect(
    hso.additionalContext,
    `additionalContext must be absent for ${firingEvent} — CC does not read it for this event`
  ).toBeUndefined();
}

// ---------------------------------------------------------------------------
// Dynamic import of the .mjs output guard
// (vitest.config.ts excludes bin/**/*.mjs from coverage but allows import)
// ---------------------------------------------------------------------------

type SanitizeFn = (result: unknown, firingEvent: string) => unknown;
let sanitizeOutput: SanitizeFn;

beforeAll(async () => {
  // Dynamic import works for .mjs in vitest ESM mode.
  // The module ships from src/hooks/bin/ (alongside run-hook.mjs) so that the
  // build's `rsync --exclude=src` still copies it to the plugin runtime.
  const guard = await import('../../bin/output-guard.mjs');
  sanitizeOutput = guard.sanitizeOutput as SanitizeFn;
});

