// ---------------------------------------------------------------------------
// sanitizeOutput unit tests (dispatcher guard in isolation)
// ---------------------------------------------------------------------------

describe('sanitizeOutput (dispatcher output guard)', () => {
  beforeEach(() => { stderrSpy.mockClear(); });

  it('passes through results with no hookSpecificOutput untouched', () => {
    const input = { continue: true, suppressOutput: true };
    expect(sanitizeOutput(input, 'WorktreeCreate')).toEqual(input);
  });

  it('strips hookEventName:UserPromptSubmit from WorktreeCreate response', () => {
    const input = {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: { hookEventName: 'UserPromptSubmit', additionalContext: 'advisory' },
    };
    const result = sanitizeOutput(input, 'WorktreeCreate') as Record<string, unknown>;
    expect(result.hookSpecificOutput).toBeUndefined();
    expect(stderrSpy).toHaveBeenCalledWith(
      expect.stringContaining('stripped hookEventName=UserPromptSubmit from WorktreeCreate')
    );
  });

  it('strips hookEventName:UserPromptSubmit from WorktreeRemove response (#1794 core)', () => {
    const input = {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: {
        hookEventName: 'UserPromptSubmit',
        additionalContext: '[WorktreeRemove] Worktree removed: /some/path',
      },
    };
    const result = sanitizeOutput(input, 'WorktreeRemove') as Record<string, unknown>;
    expect(result.hookSpecificOutput).toBeUndefined();
    expect(stderrSpy).toHaveBeenCalledWith(
      expect.stringContaining('stripped hookEventName=UserPromptSubmit from WorktreeRemove')
    );
  });

  it('preserves hookEventName:UserPromptSubmit on UserPromptSubmit events (must not strip)', () => {
    const input = {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: { hookEventName: 'UserPromptSubmit', additionalContext: 'session context' },
    };
    const result = sanitizeOutput(input, 'UserPromptSubmit') as Record<string, unknown>;
    const hso = result.hookSpecificOutput as Record<string, unknown>;
    expect(hso?.hookEventName).toBe('UserPromptSubmit');
    expect(hso?.additionalContext).toBe('session context');
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('preserves hookEventName:PreToolUse on PreToolUse events', () => {
    const input = {
      continue: true,
      suppressOutput: true,
      hookSpecificOutput: { hookEventName: 'PreToolUse', permissionDecision: 'allow', additionalContext: 'ctx' },
    };
    const result = sanitizeOutput(input, 'PreToolUse') as Record<string, unknown>;
    const hso = result.hookSpecificOutput as Record<string, unknown>;
    expect(hso?.hookEventName).toBe('PreToolUse');
    expect(hso?.additionalContext).toBe('ctx');
  });

  it('bypasses all stripping when ORCHESTKIT_DISABLE_OUTPUT_GUARD=1', () => {
    process.env.ORCHESTKIT_DISABLE_OUTPUT_GUARD = '1';
    try {
      const input = {
        continue: true,
        hookSpecificOutput: { hookEventName: 'UserPromptSubmit', additionalContext: 'advisory' },
      };
      const result = sanitizeOutput(input, 'WorktreeCreate') as Record<string, unknown>;
      const hso = result.hookSpecificOutput as Record<string, unknown>;
      expect(hso?.hookEventName).toBe('UserPromptSubmit');
      expect(stderrSpy).not.toHaveBeenCalled();
    } finally {
      delete process.env.ORCHESTKIT_DISABLE_OUTPUT_GUARD;
    }
  });

  it('does not mutate the original result object', () => {
    const input = {
      continue: true,
      hookSpecificOutput: { hookEventName: 'UserPromptSubmit', additionalContext: 'advisory' },
    };
    const originalHSO = input.hookSpecificOutput;
    sanitizeOutput(input, 'WorktreeCreate');
    // Original must be unmodified
    expect(input.hookSpecificOutput).toBe(originalHSO);
    expect(input.hookSpecificOutput.hookEventName).toBe('UserPromptSubmit');
  });
});
